// One-shot builder for /report-issue: scrubs settings, extracts Skill calls,
// composes report.md + metadata.json. Lives only inside the temp working dir.

import { readFileSync, writeFileSync, existsSync } from "node:fs";
import { join } from "node:path";
import {
  scrubSecrets,
  type ScrubMatch,
} from "/Users/ns/workspace/dev-process-toolkit/plugins/dev-process-toolkit/adapters/_shared/src/scrub_secrets.ts";
import { findCurrentSession } from "/Users/ns/workspace/dev-process-toolkit/plugins/dev-process-toolkit/adapters/_shared/src/find_current_session.ts";

const TMPDIR = "/var/folders/bq/l2fw6tpx1xg_rk2gr7klfvtw0000gn/T/report-issue-XXXXXX.kmtrNHiCcq";
const CWD = "/Users/ns/workspace/dpt-test-project-linear";

const PLUGIN_VERSION = "2.17.0";
const GIT_HEAD = "420926d5cec089d002b66f5dd89701d3573c8821";
const GIT_STATUS = ""; // clean
const GIT_LOG = `420926d chore(specs): write FR STE-246
d008b8d chore(specs): write FR STE-245
aaf347b chore(specs): propagate placeholder removal to cross-cutting specs
6d34ee1 feat(greet): add pure greet helper with whitespace fallback
b8ae663 chore(specs): write FR STE-242
64b428d chore: bootstrap dev-process-toolkit
87558d9 chore: bun init scaffold`;

// --- settings ---
const settingsPath = join(CWD, ".claude/settings.json");
const settingsLocalPath = join(CWD, ".claude/settings.local.json");

const settingsRaw = existsSync(settingsPath) ? readFileSync(settingsPath, "utf8") : null;
const settingsLocalRaw = existsSync(settingsLocalPath) ? readFileSync(settingsLocalPath, "utf8") : null;

const settingsScrub = settingsRaw ? scrubSecrets(settingsRaw) : null;
const settingsLocalScrub = settingsLocalRaw ? scrubSecrets(settingsLocalRaw) : null;

// --- session JSONL: extract Skill names (name === "Skill") ---
const sessionPath = findCurrentSession(CWD);
let skillNames: string[] = [];
let sessionAvailable = false;
if (sessionPath && existsSync(sessionPath)) {
  sessionAvailable = true;
  const lines = readFileSync(sessionPath, "utf8").split("\n").filter(Boolean);
  for (const line of lines) {
    try {
      const obj = JSON.parse(line);
      // Walk message.content for tool_use with name === "Skill"
      const content = obj?.message?.content;
      if (Array.isArray(content)) {
        for (const block of content) {
          if (block?.type === "tool_use" && block?.name === "Skill") {
            const skillArg = block?.input?.skill;
            if (typeof skillArg === "string") skillNames.push(skillArg);
          }
        }
      }
    } catch {
      // skip malformed lines
    }
  }
}

// --- aggregate redaction summary across every scrubbed artifact ---
function mergeMatches(...buckets: (ScrubMatch[] | null | undefined)[]): ScrubMatch[] {
  const acc = new Map<string, number>();
  for (const b of buckets) {
    if (!b) continue;
    for (const m of b) acc.set(m.pattern, (acc.get(m.pattern) ?? 0) + m.count);
  }
  return [...acc.entries()].map(([pattern, count]) => ({ pattern, count }));
}
const redactionSummary = mergeMatches(
  settingsScrub?.matches,
  settingsLocalScrub?.matches,
);

// --- narrative ---
const narrative = {
  whatHappened:
    "/gate-check probe #22 fails when there are uncommitted spec edits. The error message says \"modified-but-uncommitted\" but doesn't explain that probe #22 is the toolkit-bootstrap-committed probe.",
  expected:
    "Error message should identify probe #22 as the toolkit-bootstrap-committed probe and explain its purpose, so the operator knows what's being checked and why the failure happened.",
  severity: "medium",
  reproducibility:
    "Reproducible. Steps: leave a spec edit unstaged, then run /gate-check.",
};

// --- report.md ---
const skillsSection = skillNames.length > 0
  ? skillNames.map((s, i) => `${i + 1}. \`${s}\``).join("\n")
  : "_(no Skill invocations parsed from current session)_";

const reportMd = `# /report-issue — dev-process-toolkit

## Narrative

**What happened:** ${narrative.whatHappened}

**Expected:** ${narrative.expected}

## Severity

${narrative.severity}

## Reproducibility

${narrative.reproducibility}

## Curated Context

- **Plugin version:** \`${PLUGIN_VERSION}\`
- **Repo HEAD:** \`${GIT_HEAD}\`
- **Working tree:** ${GIT_STATUS.trim() === "" ? "clean (no uncommitted changes)" : "(see below)"}
${GIT_STATUS.trim() === "" ? "" : "\n```\n" + GIT_STATUS + "\n```\n"}
- **Last 10 commits:**

\`\`\`
${GIT_LOG}
\`\`\`

- **Last \`/gate-check\` log:** _(absent — \`.claude/last-gate-check.log\` not present)_

### Skills invoked this session (${skillNames.length})

${skillsSection}

### \`.claude/settings.json\` (redacted)

${settingsScrub ? "```json\n" + settingsScrub.scrubbed + "\n```" : "_(absent)_"}

### \`.claude/settings.local.json\` (redacted)

${settingsLocalScrub ? "```json\n" + settingsLocalScrub.scrubbed + "\n```" : "_(absent)_"}

## Redaction Summary

| pattern | count |
|---------|-------|
${redactionSummary.map((m) => `| \`${m.pattern}\` | ${m.count} |`).join("\n")}

_(Counts reflect pre-redaction occurrences. \`***REDACTED***\` is the post-scrub sentinel.)_
`;

writeFileSync(join(TMPDIR, "report.md"), reportMd, "utf8");

// --- metadata.json ---
const metadata = {
  timestamp: new Date().toISOString(),
  plugin_version: PLUGIN_VERSION,
  git_head: GIT_HEAD,
  severity: narrative.severity,
  redaction_summary: redactionSummary,
  full_transcript_included: false,
};
writeFileSync(
  join(TMPDIR, "metadata.json"),
  JSON.stringify(metadata, null, 2) + "\n",
  "utf8",
);

console.log("OK");
console.log("session_available=" + sessionAvailable);
console.log("session_path=" + (sessionPath ?? "null"));
console.log("skills_count=" + skillNames.length);
console.log("redaction_summary=" + JSON.stringify(redactionSummary));

